        let digitPredicate = NSPredicate(format: "SELF MATCHES %@", digitPattern)
        let specialCharPredicate = NSPredicate(format: "SELF MATCHES %@", specialCharPattern)
        
        return uppercasePredicate.evaluate(with: password) &&
